  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel AdminUser {\n  id           String   @id @default(cuid())\n  email        String   @unique\n  passwordHash String\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@map(\"admin_users\")\n}\n\nmodel User {\n  id           String   @id @default(cuid())\n  email        String   @unique\n  phoneNumber  String?  @unique\n  passwordHash String\n  firstName    String\n  lastName     String\n  isActive     Boolean  @default(true)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  ballots Ballot[]\n\n  @@map(\"users\")\n}\n\nmodel Election {\n  id          String   @id @default(cuid())\n  title       String\n  description String\n  startsAt    DateTime\n  endsAt      DateTime\n  method      String   @default(\"FPTP\") // First-Past-The-Post\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  races            Race[]            @relation(\"ElectionRaces\")\n  eligibleStudents EligibleStudent[]\n  tokens           Token[]\n  ballots          Ballot[]\n  auditLogs        AuditLog[]\n\n  @@index([startsAt])\n  @@index([endsAt])\n  @@index([createdAt])\n  @@map(\"elections\")\n}\n\nmodel Race {\n  id          String  @id @default(cuid())\n  electionId  String\n  title       String\n  maxChoices  Int     @default(1)\n  description String?\n\n  election   Election       @relation(\"ElectionRaces\", fields: [electionId], references: [id], onDelete: Cascade)\n  candidates Candidate[]\n  choices    BallotChoice[]\n\n  @@index([electionId])\n  @@map(\"races\")\n}\n\nmodel Candidate {\n  id       String  @id @default(cuid())\n  raceId   String\n  name     String\n  bio      String?\n  photoUrl String?\n\n  race    Race           @relation(fields: [raceId], references: [id], onDelete: Cascade)\n  choices BallotChoice[]\n\n  @@map(\"candidates\")\n}\n\nmodel EligibleStudent {\n  id         String  @id @default(cuid())\n  electionId String\n  externalId String // Student ID or email from CSV\n  issued     Boolean @default(false)\n\n  election Election @relation(fields: [electionId], references: [id], onDelete: Cascade)\n  tokens   Token[]\n\n  @@unique([electionId, externalId])\n  @@map(\"eligible_students\")\n}\n\nmodel Token {\n  id                String    @id @default(cuid())\n  electionId        String\n  value             String    @unique\n  issuedAt          DateTime  @default(now())\n  usedAt            DateTime?\n  expiresAt         DateTime?\n  eligibleStudentId String?\n\n  election        Election         @relation(fields: [electionId], references: [id], onDelete: Cascade)\n  eligibleStudent EligibleStudent? @relation(fields: [eligibleStudentId], references: [id], onDelete: SetNull)\n\n  @@index([value])\n  @@index([electionId])\n  @@index([usedAt])\n  @@index([expiresAt])\n  @@map(\"tokens\")\n}\n\nmodel Ballot {\n  id         String   @id @default(cuid())\n  electionId String\n  userId     String? // Link to registered users\n  castAt     DateTime @default(now())\n\n  election Election       @relation(fields: [electionId], references: [id], onDelete: Cascade)\n  user     User?          @relation(fields: [userId], references: [id], onDelete: SetNull)\n  choices  BallotChoice[]\n\n  @@index([electionId])\n  @@index([userId])\n  @@index([castAt])\n  @@map(\"ballots\")\n}\n\nmodel BallotChoice {\n  id          String @id @default(cuid())\n  ballotId    String\n  raceId      String\n  candidateId String\n  rank        Int? // For future Ranked Choice Voting\n\n  ballot    Ballot    @relation(fields: [ballotId], references: [id], onDelete: Cascade)\n  race      Race      @relation(fields: [raceId], references: [id], onDelete: Cascade)\n  candidate Candidate @relation(fields: [candidateId], references: [id], onDelete: Cascade)\n\n  @@unique([ballotId, raceId, candidateId])\n  @@map(\"ballot_choices\")\n}\n\nmodel AuditLog {\n  id         String   @id @default(cuid())\n  actor      String // Admin email or system\n  action     String // CREATE_ELECTION, GENERATE_TOKENS, etc.\n  metadata   Json? // Additional context\n  createdAt  DateTime @default(now())\n  electionId String?\n\n  election Election? @relation(fields: [electionId], references: [id])\n\n  @@map(\"audit_logs\")\n}\n",
